import sys

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def solve(self, keys: list[int], queries: list[tuple[str, int]]) -> list[int]:
        root = None
        for key in keys:
            root = self.insert(root, key)

        results = []
        for query in queries:
            if query[0] == 'S':
                results.append(self.successor(root, query[1]))
            else:
                results.append(self.predecessor(root, query[1]))
        return results

    def insert(self, root, val):
        if not root:
            return TreeNode(val)
        if val < root.val:
            root.left = self.insert(root.left, val)
        else:
            root.right = self.insert(root.right, val)
        return root

    def successor(self, root, val):
        successor = None
        while root:
            if val < root.val:
                successor = root
                root = root.left
            elif val > root.val:
                root = root.right
            else:
                root = root.right
                break
        while root:
            successor = root
            root = root.left
        return successor.val if successor else -1

    def predecessor(self, root, val):
        predecessor = None
        while root:
            if val < root.val:
                root = root.left
            elif val > root.val:
                predecessor = root
                root = root.right
            else:
                root = root.left
                break
        while root:
            predecessor = root
            root = root.right
        return predecessor.val if predecessor else -1

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        keys = [int(next(it)) for _ in range(n)]
        q = int(next(it))
        queries = [(next(it), int(next(it))) for _ in range(q)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(keys, queries)
    print("\n".join(map(str, ans)))

