#include <numeric>

#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> solve(vector<int>& keys, vector<pair<char,int>>& queries) {
        TreeNode* root = NULL;
        for (int key : keys) {
            root = insert(root, key);
        }

        vector<int> results;
        for (auto query : queries) {
            if (query.first == 'S') {
                results.push_back(successor(root, query.second));
            } else {
                results.push_back(predecessor(root, query.second));
            }
        }
        return results;
    }

    TreeNode* insert(TreeNode* root, int val) {
        if (!root) {
            return new TreeNode(val);
        }
        if (val < root->val) {
            root->left = insert(root->left, val);
        } else {
            root->right = insert(root->right, val);
        }
        return root;
    }

    int successor(TreeNode* root, int val) {
        TreeNode* successor = NULL;
        while (root) {
            if (val < root->val) {
                successor = root;
                root = root->left;
            } else if (val > root->val) {
                root = root->right;
            } else {
                root = root->right;
                break;
            }
        }
        while (root) {
            successor = root;
            root = root->left;
        }
        return successor ? successor->val : -1;
    }

    int predecessor(TreeNode* root, int val) {
        TreeNode* predecessor = NULL;
        while (root) {
            if (val < root->val) {
                root = root->left;
            } else if (val > root->val) {
                predecessor = root;
                root = root->right;
            } else {
                root = root->left;
                break;
            }
        }
        while (root) {
            predecessor = root;
            root = root->right;
        }
        return predecessor ? predecessor->val : -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> keys(n);
    for (int i = 0; i < n; i++) cin >> keys[i];
    int q;
    if (!(cin >> q)) return 0;
    vector<pair<char,int>> queries(q);
    for (int i = 0; i < q; i++) {
        char c;
        int x;
        if (!(cin >> c >> x)) return 0;
        queries[i] = make_pair(c, x);
    }
    Solution sol;
    vector<int> ans = sol.solve(keys, queries);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : "\n");
    }
    cout << "\n";
    return 0;
}
